    /* Card buttons shiny styles */
    .rr-card__btn {
        min-height: 48px;
        border: 2px solid transparent;
        border-radius: 999px !important;
        color: #fff;
        font-weight: 900 !important;
        font-size: 1.15rem;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        gap: 8px;
        padding: 0 16px;
        text-shadow: 0 2px 4px rgba(0,0,0,0.5);
    }
    .rr-card__btn--enter {
        background: linear-gradient(180deg, #f59e0b 0%, #ea580c 45%, #9a3412 100%) !important;
        border-color: #fde047 !important;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.4), inset 0 -4px 6px rgba(0, 0, 0, 0.3), 0 0 18px rgba(234, 88, 12, 0.6) !important;
    }
    .rr-card__btn--locked {
        background: linear-gradient(180deg, #e5e7eb 0%, #9ca3af 100%) !important;
        border-color: #cbd5e1 !important;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.5), inset 0 -4px 6px rgba(0, 0, 0, 0.12) !important;
        color: #111827 !important;
        text-shadow: none;
        cursor: not-allowed;
    }
    .rr-card__btn--locked i {
        color: #000;
    }
    .rr-card__btn--ranking {
        background: linear-gradient(90deg, #10b981 0%, #06b6d4 100%) !important;
        border-color: #6ee7b7 !important;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.4), inset 0 -4px 6px rgba(0, 0, 0, 0.3), 0 0 18px rgba(6, 182, 212, 0.6) !important;
    }
    .rr-card__btn--notify {
        background: linear-gradient(90deg, #1d4ed8 0%, #0f766e 100%) !important;
        border-color: #7dd3fc !important;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.28), inset 0 -4px 6px rgba(0, 0, 0, 0.26), 0 0 18px rgba(14, 165, 233, 0.34) !important;
    }
    .rr-card__btn--notify.is-active {
        background: linear-gradient(90deg, #15803d 0%, #0f766e 100%) !important;
        border-color: #86efac !important;
        color: #ecfdf5 !important;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.22), inset 0 -4px 6px rgba(0, 0, 0, 0.22), 0 0 18px rgba(34, 197, 94, 0.34) !important;
    }
    .rr-card__btn i {
        font-size: 1.15em;
    }

    /* Enhanced Arena Gateway Styles */
    .rr-arena-gateway__status {
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        gap: 12px;
    }

    .status-badge {
        padding: 10px 16px;
        border-radius: 999px;
        background: rgba(249, 115, 22, 0.1);
        border: 1px solid rgba(249, 115, 22, 0.3);
        color: #f97316;
        font-weight: 700;
        font-size: 0.85rem;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    }

    .status-badge:hover {
        background: rgba(249, 115, 22, 0.2);
        border-color: rgba(249, 115, 22, 0.6);
        transform: translateY(-2px);
        box-shadow: 0 8px 20px rgba(249, 115, 22, 0.2);
    }

    .rr-arena-card {
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    }

    .rr-arena-card__tag {
        display: inline-flex;
        align-items: center;
        gap: 8px;
        font-weight: 700;
        padding: 8px 12px;
        border-radius: 999px;
        font-size: 0.75rem;
        letter-spacing: 0.05em;
        text-transform: uppercase;
    }

    .rr-arena-card__button {
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    }

    .rr-arena-card__button:hover {
        transform: translateY(-2px);
        box-shadow: 0 12px 30px rgba(249, 115, 22, 0.3);
    }

    .rr-arena-card__media img,
    .rr-arena-card__icon {
        transition: all 0.3s ease;
    }

    .rr-arena-card__title {
        font-size: clamp(1.8rem, 4vw, 2.4rem);
    }

    /* Glass effect for cards */
    .rr-arena-card.glass-card {
        background: rgba(15, 23, 42, 0.5);
        backdrop-filter: blur(14px);
        border: 1px solid rgba(255, 255, 255, 0.1);
    }

    .rr-arena-card.glass-card:hover {
        background: rgba(15, 23, 42, 0.7);
        border-color: rgba(249, 115, 22, 0.3);
    }

    .rr-mobile-actions {
