        -webkit-mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
        -webkit-mask-composite: xor;
        mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
        mask-composite: exclude;
    }

    .rr-sponsor-ring:nth-child(1) { --ring-inset: -4px; --ring-width: 2px; --ring-blur: 0px; --ring-opacity: .62; --ring-speed: 14s; }
    .rr-sponsor-ring:nth-child(2) { --ring-inset: 11px; --ring-width: 1px; --ring-blur: 1px; --ring-opacity: .44; --ring-speed: 22s; animation-direction: reverse; }
    .rr-sponsor-ring:nth-child(3) { --ring-inset: -19px; --ring-width: 1px; --ring-blur: 3px; --ring-opacity: .30; --ring-speed: 30s; }

    .rr-sponsor-particles {
        z-index: 4;
        overflow: hidden;
        border-radius: 28px;
    }

    .rr-sponsor-particle {
        position: absolute;
        left: var(--x);
        bottom: 15%;
        width: var(--size);
        height: var(--size);
        border-radius: 999px;
        background: var(--color);
        box-shadow: 0 0 14px var(--color);
        opacity: 0;
        transform: translate3d(0, 0, 0) scale(.7);
        animation: rrSponsorParticleRise var(--duration) var(--delay) ease-out infinite;
        will-change: transform, opacity;
    }

    .rr-logo-wrap.is-sponsor-showcase {
        border-color: rgba(251,191,36,.28);
        background:
            radial-gradient(circle at var(--rr-logo-mx) var(--rr-logo-my), rgba(255,255,255,.12), transparent 24%),
            linear-gradient(180deg, rgba(255,255,255,.07), rgba(255,255,255,.018)),
            linear-gradient(180deg, rgba(7,12,25,.98), rgba(2,6,23,.98));
        box-shadow: 0 22px 55px rgba(0,0,0,.42), 0 0 42px rgba(56,189,248,.14), inset 0 1px 0 rgba(255,255,255,.14), inset 0 -18px 38px rgba(0,0,0,.32);
    }

    .rr-logo-wrap.is-sponsor-showcase .rr-sponsor-orbit,
    .rr-logo-wrap.is-sponsor-showcase .rr-sponsor-particles,
    .rr-logo-wrap.is-sponsor-showcase .rr-sponsor-aura {
        opacity: 1;
    }

    .rr-logo-wrap.is-sponsor-showcase .rr-logo {
        filter: drop-shadow(0 0 10px rgba(255,255,255,.18)) drop-shadow(0 0 20px rgba(56,189,248,.20));
    }

    .rr-logo-wrap.is-sponsor-showcase:hover,
    .rr-logo-wrap.is-sponsor-showcase.is-touching {
        transform: scale(1.045) translateZ(0);
        border-color: rgba(251,191,36,.46);
        box-shadow: 0 26px 70px rgba(0,0,0,.48), 0 0 64px rgba(251,191,36,.18), 0 0 42px rgba(56,189,248,.20), inset 0 1px 0 rgba(255,255,255,.18);
    }

    .rr-logo-wrap.is-sponsor-showcase:hover .rr-sponsor-aura,
    .rr-logo-wrap.is-sponsor-showcase.is-touching .rr-sponsor-aura {
        animation-duration: 2.8s;
        filter: blur(22px) saturate(1.28);
    }

    .rr-logo-wrap.is-sponsor-showcase:hover .rr-sponsor-ring,
    .rr-logo-wrap.is-sponsor-showcase.is-touching .rr-sponsor-ring {
        animation-duration: calc(var(--ring-speed) * .55), 3.2s;
    }

    .rr-logo-wrap.is-sponsor-showcase:hover .rr-sponsor-particle,
    .rr-logo-wrap.is-sponsor-showcase.is-touching .rr-sponsor-particle {
        animation-duration: calc(var(--duration) * .62);
    }

    @keyframes rrSponsorAura {
        0%, 100% {
            opacity: .56;
            transform: translateZ(0) scale(.92);
            background: radial-gradient(circle at var(--rr-logo-mx) var(--rr-logo-my), rgba(255,255,255,.14), transparent 24%), radial-gradient(circle, rgba(56,189,248,.24), transparent 46%), radial-gradient(circle, rgba(251,191,36,.12), transparent 62%);
        }
        45% {
            opacity: .98;
            transform: translateZ(0) scale(1.12);
            background: radial-gradient(circle at var(--rr-logo-mx) var(--rr-logo-my), rgba(255,255,255,.18), transparent 24%), radial-gradient(circle, rgba(139,92,246,.30), transparent 48%), radial-gradient(circle, rgba(251,191,36,.22), transparent 64%);
        }
        72% {
            opacity: .80;
            transform: translateZ(0) scale(1.02);
            background: radial-gradient(circle at var(--rr-logo-mx) var(--rr-logo-my), rgba(255,255,255,.14), transparent 24%), radial-gradient(circle, rgba(251,191,36,.26), transparent 48%), radial-gradient(circle, rgba(56,189,248,.16), transparent 64%);
        }
    }

    @keyframes rrSponsorRingSpin { to { transform: rotate(360deg) translateZ(0); } }
    @keyframes rrSponsorRingFade { 0%, 100% { opacity: var(--ring-opacity); } 50% { opacity: calc(var(--ring-opacity) * .42); } }
    @keyframes rrSponsorParticleRise {
        0% { opacity: 0; transform: translate3d(0,0,0) scale(.65); }
        12% { opacity: .88; }
        100% { opacity: 0; transform: translate3d(var(--drift), calc(var(--rise) * -1), 0) scale(.08); }
    }

    @media (prefers-reduced-motion: reduce) {
        .rr-sponsor-aura,
        .rr-sponsor-ring,
        .rr-sponsor-particle {
            animation: none;
        }

        .rr-sponsor-particle {
            display: none;
        }
    }

    .rr-cards {
        position: relative;
        isolation: isolate;
        overflow: hidden;
    }

    .rr-cards::before {
        content: "";
        position: absolute;
        inset: -35% -18%;
        z-index: 0;
        pointer-events: none;
        background:
            radial-gradient(circle at 18% 24%, rgba(56,189,248,.12), transparent 32%),
            radial-gradient(circle at 82% 12%, rgba(139,92,246,.11), transparent 30%),
            radial-gradient(circle at 58% 92%, rgba(251,191,36,.09), transparent 34%);
        filter: blur(8px) saturate(1.1);
        opacity: .82;
        animation: rrCardsAmbientDrift 13s ease-in-out infinite;
        will-change: transform, opacity;
    }

    .rr-cards::after {
        content: "";
        position: absolute;
        inset: 0;
        z-index: 4;
        pointer-events: none;
        background:
            linear-gradient(90deg, transparent, rgba(255,255,255,.05), transparent),
            radial-gradient(circle at center, transparent 0 44%, rgba(2,6,23,.38) 100%);
        opacity: .52;
        mix-blend-mode: screen;
    }

    .rr-cards__particles {
        position: absolute;
        inset: 0;
        z-index: 5;
        overflow: hidden;
        pointer-events: none;
        border-radius: inherit;
        mix-blend-mode: screen;
    }

    .rr-cards__particle {
        position: absolute;
        left: var(--x);
        bottom: var(--y);
        width: var(--size);
        height: var(--size);
        border-radius: 999px;
        background: var(--color);
        box-shadow: 0 0 12px var(--color), 0 0 28px var(--color);
        opacity: 0;
        transform: translate3d(0,0,0) scale(.7);
        animation: rrCardsParticleRise var(--duration) var(--delay) ease-out infinite;
        will-change: transform, opacity;
    }

    .rr-cards__particle:nth-child(4n) {
        border-radius: 2px;
        transform: translate3d(0,0,0) rotate(45deg) scale(.7);
    }

    .rr-cards__particle:nth-child(3n) {
        filter: blur(.5px);
    }

    .rr-cards__grid {
        position: relative;
        z-index: 3;
    }

    @keyframes rrCardsAmbientDrift {
        0%, 100% { opacity: .62; transform: translate3d(-1.5%, -1%, 0) scale(1); }
        46% { opacity: .92; transform: translate3d(1.5%, 1%, 0) scale(1.04); }
        72% { opacity: .76; transform: translate3d(.5%, -1.2%, 0) scale(1.02); }
    }

    @keyframes rrCardsParticleRise {
        0% { opacity: 0; transform: translate3d(0,0,0) scale(.62) rotate(var(--rotate)); }
        14% { opacity: var(--peak); }
        100% { opacity: 0; transform: translate3d(var(--drift), calc(var(--rise) * -1), 0) scale(.12) rotate(calc(var(--rotate) + 90deg)); }
    }

    @media (prefers-reduced-motion: reduce) {
        .rr-cards::before,
        .rr-cards__particle {
            animation: none;
        }

        .rr-cards__particle {
            display: none;
        }
    }

    .rr-side__controls {
        display: grid;
        gap: 10px;
        margin-top: 4px;
    }

    .rr-side__nav {
        display: none;
        grid-template-columns: repeat(4, minmax(0, 1fr));
        gap: 8px;
        margin-top: 18px;
        width: min(100%, 480px);
    }

    .rr-side__nav-btn {
        min-height: 44px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        gap: 6px;
        padding: 0 8px;
        border-radius: 999px;
        text-decoration: none;
        color: #fff;
        font-weight: 900;
        font-size: 0.85rem;
        border: 2px solid transparent;
        text-shadow: 0 2px 4px rgba(0,0,0,0.5);
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.4), inset 0 -4px 6px rgba(0, 0, 0, 0.3);
    }

    .rr-side__nav-profile {
        background: linear-gradient(90deg, #10b981 0%, #06b6d4 100%);
        border-color: #6ee7b7;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.4), inset 0 -4px 6px rgba(0, 0, 0, 0.3), 0 0 18px rgba(6, 182, 212, 0.6);
    }

    .rr-side__nav-pix {
        background: linear-gradient(180deg, #f59e0b 0%, #ea580c 45%, #9a3412 100%);
        border-color: #fde047;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.4), inset 0 -4px 6px rgba(0, 0, 0, 0.3), 0 0 18px rgba(234, 88, 12, 0.6);
    }

    .rr-side__nav-rules {
        background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%);
        border-color: #fbbf24;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.38), inset 0 -4px 6px rgba(0, 0, 0, 0.28), 0 0 18px rgba(245, 158, 11, 0.48);
    }

    .rr-side__nav-support {
        background: linear-gradient(90deg, #10b981 0%, #06b6d4 100%);
        border-color: #6ee7b7;
        box-shadow: inset 0 2px 5px rgba(255, 255, 255, 0.38), inset 0 -4px 6px rgba(0, 0, 0, 0.28), 0 0 18px rgba(6, 182, 212, 0.48);
    }

    .rr-mobile-refresh-fab {
        display: none;
    }

    .rr-card__prize-wrap {
        position: relative;
        margin-top: 14px;
        min-height: 138px;
        overflow: hidden;
        border-radius: 24px;
        padding: 14px 14px 12px;
        background:
            radial-gradient(circle at 50% 110%, rgba(16, 185, 129, 0.24), transparent 44%),
            radial-gradient(circle at 18% 0%, rgba(20, 83, 45, 0.42), transparent 46%),
            linear-gradient(180deg, rgba(3, 36, 24, 0.92), rgba(2, 20, 17, 0.97));
        border: 1px solid rgba(34, 197, 94, 0.42);
        box-shadow:
            inset 0 1px 0 rgba(209, 250, 229, 0.22),
            inset 0 -14px 24px rgba(0, 0, 0, 0.32),
            0 0 26px rgba(16, 185, 129, 0.22);
    }

    .rr-card__prize-wrap::before,
    .rr-card__prize-wrap::after {
        content: "";
        position: absolute;
        inset: auto 7% 10px;
        height: 3px;
        border-radius: 999px;
        background: linear-gradient(90deg, transparent, rgba(110, 231, 183, 0.86), rgba(34, 197, 94, 0.92), transparent);
        filter: blur(0.4px);
        opacity: 0.9;
        z-index: 2;
    }

    .rr-card__prize-wrap::after {
        inset: 10px 7% auto;
        opacity: 0.5;
    }

    .rr-card__prize-label {
        position: relative;
        z-index: 7;
        width: fit-content;
        margin: 0 auto 8px;
        padding: 4px 16px;
        border-radius: 999px;
        border: 1px solid rgba(110, 231, 183, 0.6);
        background: linear-gradient(180deg, rgba(6, 78, 59, 0.92), rgba(2, 44, 34, 0.94));
        color: #bbf7d0;
        font-size: 0.74rem;
        font-weight: 900;
        letter-spacing: 0.16em;
        text-transform: uppercase;
        text-shadow: 0 0 10px rgba(34, 197, 94, 0.42);
        box-shadow: 0 0 16px rgba(16, 185, 129, 0.2);
    }

    .rr-card__prize-frame {
        position: relative;
        z-index: 6;
        min-height: 84px;
        display: grid;
        place-items: center;
        gap: 4px;
        border-radius: 22px;
        padding: 12px 16px;
        background: linear-gradient(180deg, rgba(5, 46, 34, 0.74), rgba(2, 24, 20, 0.84));
        border: 2px solid rgba(74, 222, 128, 0.7);
        box-shadow:
            inset 0 0 0 2px rgba(209, 250, 229, 0.14),
            0 0 24px rgba(16, 185, 129, 0.26),
            0 0 42px rgba(5, 150, 105, 0.18);
    }

    .rr-card__prize-value {
        position: relative;
        z-index: 3;
        color: #dcfce7;
        font-size: clamp(1.8rem, 2.8vw, 2.45rem);
        font-weight: 900;
        letter-spacing: -0.07em;
        line-height: 1;
        text-shadow:
            0 0 12px rgba(74, 222, 128, 0.5),
            0 2px 8px rgba(0, 0, 0, 0.45);
    }

    .rr-card__prize-value--text {
        max-width: 100%;
        font-size: 1.05rem;
        letter-spacing: 0;
        line-height: 1.18;
        text-align: center;
        overflow: hidden;
        display: -webkit-box;
        -webkit-line-clamp: 2;
        -webkit-box-orient: vertical;
    }

    .rr-card__prize-current {
        position: relative;
        z-index: 3;
        color: #d6d3d1;
        font-size: 0.76rem;
        font-weight: 800;
        margin-top: 2px;
        text-transform: uppercase;
        letter-spacing: 0.05em;
        text-shadow: 0 1px 3px rgba(0, 0, 0, 0.4);
    }

    .rr-card__prize-current .rr-slot-prize {
        color: #f5f5f4;
    }

    .rr-card__particles {
        position: absolute;
        inset: 0;
        pointer-events: none;
        z-index: 4;
        overflow: hidden;
        mix-blend-mode: screen;
    }

    .rr-card__particle {
        position: absolute;
        left: var(--x);
        bottom: -8px;
        width: var(--size);
        height: var(--size);
        border-radius: 999px;
        opacity: 0;
        background: radial-gradient(circle, rgba(220, 252, 231, 0.94) 0%, rgba(74, 222, 128, 0.76) 36%, rgba(5, 150, 105, 0.2) 72%, transparent 100%);
        filter: blur(var(--blur));
        box-shadow: 0 0 8px rgba(110, 231, 183, 0.65), 0 0 18px rgba(16, 185, 129, 0.34);
        transform: translate3d(0, 0, 0) scale(0.72);
        animation: rrPrizeRise var(--duration) ease-out infinite;
        animation-delay: var(--delay);
    }

    @media (max-width: 767px) {
        .rr-card__particles {
            z-index: 5;
        }

        .rr-card__particle {
            width: calc(var(--size) * 1.18);
            height: calc(var(--size) * 1.18);
            box-shadow: 0 0 10px rgba(110, 231, 183, 0.7), 0 0 24px rgba(16, 185, 129, 0.42);
        }
    }

    @keyframes rrPrizeRise {
        0% {
            transform: translate3d(0, 0, 0) scale(0.72);
            opacity: 0;
        }
        14% {
            opacity: 0.78;
        }
        100% {
            transform: translate3d(var(--drift), -124px, 0) scale(1.18);
            opacity: 0;
        }
    }

